('a1b2c3d4-0002-0002-0002-0000000000ba', '白露：蒹葭苍苍', '节气', '天气转凉，露水凝白。', '白露是二十四节气中的第十五个节气，秋季的第三个节气。天气渐凉，露水凝结为白色。', '白露是二十四节气中的第十五个节气，秋季的第三个节气。天气渐凉，露水凝结为白色。', '💧', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','白露'], 678, '白露：蒹葭苍苍源远流长，可上溯至先秦时期。天气转凉、露水凝白、其形成与演变深受历代政治、经济、文化之影响。', '白露：蒹葭苍苍作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"白露：蒹葭苍苍是什么？","answer":"天气转凉，露水凝白。"},{"question":"白露：蒹葭苍苍起源于何时？","answer":"根据史料记载，白露：蒹葭苍苍的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"白露：蒹葭苍苍有什么文化意义？","answer":"白露：蒹葭苍苍承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-02-04T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 处暑：暑气将止
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-00000000000c', '处暑：暑气将止', '节气', '暑气至此而止，凉秋将至。', '处暑是二十四节气中的第十四个节气，秋季的第二个节气。''处''有躲藏、终止之意，处暑即暑气将止。', '处暑是二十四节气中的第十四个节气，秋季的第二个节气。''处''有躲藏、终止之意，处暑即暑气将止。', '🍃', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','处暑'], 534, '处暑：暑气将止源远流长，可上溯至先秦时期。暑气至此而止、凉秋将至、其形成与演变深受历代政治、经济、文化之影响。', '处暑：暑气将止作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"处暑：暑气将止是什么？","answer":"暑气至此而止，凉秋将至。"},{"question":"处暑：暑气将止起源于何时？","answer":"根据史料记载，处暑：暑气将止的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"处暑：暑气将止有什么文化意义？","answer":"处暑：暑气将止承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-05-13T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 春分：昼夜平分
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-00000000000c', '春分：昼夜平分', '节气', '太阳直射赤道，昼夜等长，春意盎然。', '春分是春季九十天的中分点，此时太阳直射地球赤道，全球昼夜几乎等长。春分三候：玄鸟至、雷乃发声、始电。民间有''春分竖蛋''的习俗。', '春分是春季九十天的中分点，此时太阳直射地球赤道，全球昼夜几乎等长。春分三候：玄鸟至、雷乃发声、始电。民间有''春分竖蛋''的习俗。', '⚖️', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','春分'], 1456, '春分：昼夜平分源远流长，可上溯至先秦时期。太阳直射赤道、昼夜等长、春意盎然、其形成与演变深受历代政治、经济、文化之影响。', '春分：昼夜平分作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"春分：昼夜平分是什么？","answer":"太阳直射赤道，昼夜等长，春意盎然。"},{"question":"春分：昼夜平分起源于何时？","answer":"根据史料记载，春分：昼夜平分的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"春分：昼夜平分有什么文化意义？","answer":"春分：昼夜平分承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-02-16T06:06:26.222Z')
