-- 大寒：岁末严寒
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-0000000000da', '大寒：岁末严寒', '节气', '一年中最寒冷的节气，二十四节气收官。', '大寒是二十四节气中的最后一个节气，是天气寒冷到极点的意思。此时天气寒冷至极，民间有''大寒迎年''之说。', '大寒是二十四节气中的最后一个节气，是天气寒冷到极点的意思。此时天气寒冷至极，民间有''大寒迎年''之说。', '☃', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','大寒'], 489, '大寒：岁末严寒源远流长，可上溯至先秦时期。一年中最寒冷的节气、二十四节气收官、其形成与演变深受历代政治、经济、文化之影响。', '大寒：岁末严寒作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"大寒：岁末严寒是什么？","answer":"一年中最寒冷的节气，二十四节气收官。"},{"question":"大寒：岁末严寒起源于何时？","answer":"根据史料记载，大寒：岁末严寒的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"大寒：岁末严寒有什么文化意义？","answer":"大寒：岁末严寒承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-04-24T06:06:26.222Z')
