-- 大暑：盛夏之极
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-0000000000da', '大暑：盛夏之极', '节气', '一年中最炎热的时节，雷雨频繁，万物生长最快。', '大暑是二十四节气中的第十二个节气，夏季的最后一个节气。一般在公历7月22日或23日，正值''三伏天''的中伏前后，是一年中最热的时候。', '大暑是二十四节气中的第十二个节气，夏季的最后一个节气。一般在公历7月22日或23日，正值''三伏天''的中伏前后，是一年中最热的时候。', '🔥', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','大暑'], 723, '大暑：盛夏之极源远流长，可上溯至先秦时期。一年中最炎热的时节、雷雨频繁、万物生长最快、其形成与演变深受历代政治、经济、文化之影响。', '大暑：盛夏之极作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"大暑：盛夏之极是什么？","answer":"一年中最炎热的时节，雷雨频繁，万物生长最快。"},{"question":"大暑：盛夏之极起源于何时？","answer":"根据史料记载，大暑：盛夏之极的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"大暑：盛夏之极有什么文化意义？","answer":"大暑：盛夏之极承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2025-12-17T06:06:26.222Z')
