-- 大雪：瑞雪兆丰年
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-0000000000da', '大雪：瑞雪兆丰年', '节气', '降雪量增大，千里冰封，万里雪飘。', '大雪是二十四节气中的第二十一个节气，意味着天气更冷，降雪的可能性比小雪时更大了，往往能够见到较大的降雪。', '大雪是二十四节气中的第二十一个节气，意味着天气更冷，降雪的可能性比小雪时更大了，往往能够见到较大的降雪。', '❄', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','大雪'], 745, '大雪：瑞雪兆丰年源远流长，可上溯至先秦时期。降雪量增大、千里冰封、万里雪飘、其形成与演变深受历代政治、经济、文化之影响。', '大雪：瑞雪兆丰年作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '北方', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"大雪：瑞雪兆丰年是什么？","answer":"降雪量增大，千里冰封，万里雪飘。"},{"question":"大雪：瑞雪兆丰年起源于何时？","answer":"根据史料记载，大雪：瑞雪兆丰年的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"大雪：瑞雪兆丰年有什么文化意义？","answer":"大雪：瑞雪兆丰年承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-01-17T06:06:26.222Z')
