-- 冬至：阳气始生
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-00000000000d', '冬至：阳气始生', '节气', '白昼最短，夜晚最长，一阳初生。', '冬至是二十四节气中的第二十二个节气，这一天北半球白昼最短、夜晚最长。民间有''冬至大如年''之说。', '冬至是二十四节气中的第二十二个节气，这一天北半球白昼最短、夜晚最长。民间有''冬至大如年''之说。', '🌞', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','冬至'], 1567, '冬至：阳气始生源远流长，可上溯至先秦时期。白昼最短、夜晚最长、一阳初生、其形成与演变深受历代政治、经济、文化之影响。', '冬至：阳气始生作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"冬至：阳气始生是什么？","answer":"白昼最短，夜晚最长，一阳初生。"},{"question":"冬至：阳气始生起源于何时？","answer":"根据史料记载，冬至：阳气始生的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"冬至：阳气始生有什么文化意义？","answer":"冬至：阳气始生承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-03-12T06:06:26.222Z')
