-- 谷雨：雨生百谷
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000001', '谷雨：雨生百谷', '节气', '春季最后一个节气，源自''雨生百谷''之说，是播种移苗的关键时令。', '谷雨是二十四节气中的第六个节气，也是春季的最后一个节气。《月令七十二候集解》中说：''三月中，自雨水后，土膏脉动，今又雨其谷于水也。''', '谷雨是二十四节气中的第六个节气，也是春季的最后一个节气。《月令七十二候集解》中说：''三月中，自雨水后，土膏脉动，今又雨其谷于水也。''', '🌧', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','谷雨'], 1284, '谷雨：雨生百谷源远流长，可上溯至先秦时期。春季最后一个节气、源自''雨生百谷''之说、是播种移苗的关键时令、其形成与演变深受历代政治、经济、文化之影响。', '谷雨：雨生百谷作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '汉', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"谷雨：雨生百谷是什么？","answer":"春季最后一个节气，源自''雨生百谷''之说，是播种移苗的关键时令。"},{"question":"谷雨：雨生百谷起源于何时？","answer":"根据史料记载，谷雨：雨生百谷的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"谷雨：雨生百谷有什么文化意义？","answer":"谷雨：雨生百谷承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-02-28T06:06:26.222Z')
