-- 惊蛰：春雷初响
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '惊蛰：春雷初响', '节气', '春雷惊醒蛰伏的动物，大地焕发生机。', '惊蛰，古称''启蛰''，是二十四节气中的第三个节气。春雷初响，惊醒了蛰伏在土中冬眠的动物。惊蛰三候：桃始华、仓庚鸣、鹰化为鸠。', '惊蛰，古称''启蛰''，是二十四节气中的第三个节气。春雷初响，惊醒了蛰伏在土中冬眠的动物。惊蛰三候：桃始华、仓庚鸣、鹰化为鸠。', '🌩', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','惊蛰'], 1123, '惊蛰：春雷初响源远流长，可上溯至先秦时期。春雷惊醒蛰伏的动物、大地焕发生机、其形成与演变深受历代政治、经济、文化之影响。', '惊蛰：春雷初响作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '汉', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"惊蛰：春雷初响是什么？","answer":"春雷惊醒蛰伏的动物，大地焕发生机。"},{"question":"惊蛰：春雷初响起源于何时？","answer":"根据史料记载，惊蛰：春雷初响的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"惊蛰：春雷初响有什么文化意义？","answer":"惊蛰：春雷初响承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2025-12-12T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 立春：东风解冻
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '立春：东风解冻', '节气', '二十四节气之首，春天的开始，有''咬春''、''打春牛''等习俗。', '立春，是二十四节气中的第一个节气。''立''是''开始''之意，''春''代表着温暖、生长。古时人们在立春这天有''迎春''、''咬春''（吃春饼春卷）、''鞭春牛''（劝农耕作）等仪式。立春三候：东风解冻、蛰虫始振、鱼陟负冰。', '立春，是二十四节气中的第一个节气。''立''是''开始''之意，''春''代表着温暖、生长。古时人们在立春这天有''迎春''、''咬春''（吃春饼春卷）、''鞭春牛''（劝农耕作）等仪式。立春三候：东风解冻、蛰虫始振、鱼陟负冰。', '🌱', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','立春','春季'], 1256, '立春作为节气，最早可溯至先秦。《吕氏春秋·十二月纪》已有立春记载，《淮南子·天文训》完整确立了二十四节气体系，将立春列为节气之首。汉代始有天子率三公九卿于东郊迎春之礼，唐宋以降，''鞭春牛''、''咬春''等民俗盛行，至明清时期逐渐演变为今日所见之节俗形态。', '立春所承载的''生生之德''与''天人相应''哲学，深刻塑造了中华文明的时间观与生命观。其''东风解冻''意象成为文学艺术永恒母题；''咬春''''打春''等习俗至今活跃于民间，成为连接传统与现代的文化纽带。2016年''二十四节气''入选联合国非遗名录，立春作为首项，更成为中国向世界传递''尊重自然、顺应天时''东方智慧的重要符号。', '上古', '周', '中原', '[{"id":"kongzi","title":"孔子","category":"人物","brief":"儒家始祖，《礼记·月令》传其思想"}]'::jsonb, '[{"id":"lunyu","title":"《论语》","category":"典籍","brief":"儒家经典，立春之礼多有体现","external":true,"externalUrl":"https://baike.baidu.com/item/论语"},{"id":"liji","title":"《礼记》","category":"典籍","brief":"《月令》篇详载立春仪轨","external":true,"externalUrl":"https://baike.baidu.com/item/礼记"}]'::jsonb, '[{"id":"evt_bianchunniu","title":"鞭春牛","brief":"立春劝农仪式，源远流长"}]'::jsonb, '[{"id":"chunyexiyu","title":"春夜喜雨","category":"诗词","brief":"杜甫咏春雨名篇"},{"id":"yuansheng","title":"元日","category":"诗词","brief":"王安石''爆竹声中一岁除''","external":true,"externalUrl":"https://baike.baidu.com/item/元日"}]'::jsonb, '[{"id":"yushui","title":"雨水：润物细无声","category":"节气"},{"id":"chunjie","title":"春节：辞旧迎新","category":"节日"}]'::jsonb, '[{"question":"立春就是春节吗？","answer":"不是。立春是节气，发生在公历2月3-5日；春节是农历正月初一。两者日期常常接近但概念不同。","link":"chunjie"},{"question":"立春为什么要''咬春''？","answer":"咬春指吃春饼、春卷、萝卜等，取''咬得草根断，则百事可做''之意，象征以新生事物咬住春天。","link":"chunyexiyu"},{"question":"立春有哪些禁忌？","answer":"民间认为立春这天不宜看病、搬家、动土，部分属相者需''躲春''以避气场不稳。"}]'::jsonb, '2026-04-08T06:06:26.221Z')
ON CONFLICT (id) DO NOTHING;

-- 立冬：万物收藏
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '立冬：万物收藏', '节气', '冬季的开始，万物归藏，避寒保暖。', '立冬是二十四节气中的第十九个节气，冬季的第一个节气。''立''是开始之意，冬是终了、万物收藏的意思。立冬三候：水始冰、地始冻、雉入大水为蜃。', '立冬是二十四节气中的第十九个节气，冬季的第一个节气。''立''是开始之意，冬是终了、万物收藏的意思。立冬三候：水始冰、地始冻、雉入大水为蜃。', '🌨', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','立冬'], 1023, '立冬：万物收藏源远流长，可上溯至先秦时期。冬季的开始、万物归藏、避寒保暖、其形成与演变深受历代政治、经济、文化之影响。', '立冬：万物收藏作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"立冬：万物收藏是什么？","answer":"冬季的开始，万物归藏，避寒保暖。"},{"question":"立冬：万物收藏起源于何时？","answer":"根据史料记载，立冬：万物收藏的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"立冬：万物收藏有什么文化意义？","answer":"立冬：万物收藏承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2025-12-18T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 立秋：凉风至
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '立秋：凉风至', '节气', '秋季的开始，暑去凉来，万物开始成熟。', '立秋是二十四节气中的第十三个节气，秋季的第一个节气。''立''是开始之意，''秋''意味着暑去凉来。立秋三候：凉风至、白露降、寒蝉鸣。', '立秋是二十四节气中的第十三个节气，秋季的第一个节气。''立''是开始之意，''秋''意味着暑去凉来。立秋三候：凉风至、白露降、寒蝉鸣。', '🍂', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','立秋'], 1156, '立秋：凉风至源远流长，可上溯至先秦时期。秋季的开始、暑去凉来、万物开始成熟、其形成与演变深受历代政治、经济、文化之影响。', '立秋：凉风至作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"立秋：凉风至是什么？","answer":"秋季的开始，暑去凉来，万物开始成熟。"},{"question":"立秋：凉风至起源于何时？","answer":"根据史料记载，立秋：凉风至的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"立秋：凉风至有什么文化意义？","answer":"立秋：凉风至承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-03-05T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 芒种：忙种忙收
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '芒种：忙种忙收', '节气', '农事最忙的节气，南方种稻、北方收麦。', '芒种是二十四节气中的第九个节气，夏季的第三个节气。字面意思是''有芒的麦子快收，有芒的稻子可种''，是一个既涉及收获又涉及播种的节气。', '芒种是二十四节气中的第九个节气，夏季的第三个节气。字面意思是''有芒的麦子快收，有芒的稻子可种''，是一个既涉及收获又涉及播种的节气。', '🌱', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','芒种'], 645, '芒种：忙种忙收源远流长，可上溯至先秦时期。农事最忙的节气、南方种稻、北方收麦、其形成与演变深受历代政治、经济、文化之影响。', '芒种：忙种忙收作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"芒种：忙种忙收是什么？","answer":"农事最忙的节气，南方种稻、北方收麦。"},{"question":"芒种：忙种忙收起源于何时？","answer":"根据史料记载，芒种：忙种忙收的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"芒种：忙种忙收有什么文化意义？","answer":"芒种：忙种忙收承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-03-30T06:06:26.222Z')
