-- 清明：气清景明
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '清明：气清景明', '节气', '二十四节气之一，兼具自然与人文内涵，是祭祖踏青的传统节日。', '清明，是二十四节气中的第五个节气，一般在公历4月4日至6日之间。''清明''意为''天清气明''，此时气候清爽温暖，草木萌发，自然界一派生机勃勃。', '清明，是二十四节气中的第五个节气，一般在公历4月4日至6日之间。''清明''意为''天清气明''，此时气候清爽温暖，草木萌发，自然界一派生机勃勃。', '🌿', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','清明'], 1823, '清明：气清景明源远流长，可上溯至先秦时期。二十四节气之一、兼具自然与人文内涵、是祭祖踏青的传统节日、其形成与演变深受历代政治、经济、文化之影响。', '清明：气清景明作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '春秋', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"清明：气清景明是什么？","answer":"二十四节气之一，兼具自然与人文内涵，是祭祖踏青的传统节日。"},{"question":"清明：气清景明起源于何时？","answer":"根据史料记载，清明：气清景明的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"清明：气清景明有什么文化意义？","answer":"清明：气清景明承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-03-13T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 秋分：昼夜均分
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '秋分：昼夜均分', '节气', '秋季九十天之半，昼夜再次等长。', '秋分是二十四节气中的第十六个节气，这一天太阳直射赤道，昼夜几乎等长。此后北半球昼短夜长，天气渐凉。', '秋分是二十四节气中的第十六个节气，这一天太阳直射赤道，昼夜几乎等长。此后北半球昼短夜长，天气渐凉。', '🌗', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','秋分'], 894, '秋分：昼夜均分源远流长，可上溯至先秦时期。秋季九十天之半、昼夜再次等长、其形成与演变深受历代政治、经济、文化之影响。', '秋分：昼夜均分作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"秋分：昼夜均分是什么？","answer":"秋季九十天之半，昼夜再次等长。"},{"question":"秋分：昼夜均分起源于何时？","answer":"根据史料记载，秋分：昼夜均分的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"秋分：昼夜均分有什么文化意义？","answer":"秋分：昼夜均分承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-06-07T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 霜降：秋尽冬来
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '霜降：秋尽冬来', '节气', '秋季最后一个节气，初霜出现，天气渐冷。', '霜降是二十四节气中的第十八个节气，秋季的最后一个节气。含有天气渐冷、初霜出现的意思，是秋季与冬季的过渡节气。', '霜降是二十四节气中的第十八个节气，秋季的最后一个节气。含有天气渐冷、初霜出现的意思，是秋季与冬季的过渡节气。', '❄', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','霜降'], 612, '霜降：秋尽冬来源远流长，可上溯至先秦时期。秋季最后一个节气、初霜出现、天气渐冷、其形成与演变深受历代政治、经济、文化之影响。', '霜降：秋尽冬来作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '黄河流域', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"霜降：秋尽冬来是什么？","answer":"秋季最后一个节气，初霜出现，天气渐冷。"},{"question":"霜降：秋尽冬来起源于何时？","answer":"根据史料记载，霜降：秋尽冬来的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"霜降：秋尽冬来有什么文化意义？","answer":"霜降：秋尽冬来承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-01-25T06:06:26.222Z')
