-- 夏至：日北至
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '夏至：日北至', '节气', '北半球白昼最长的一天，盛夏的开始。', '夏至是二十四节气中的第十个节气，这一天太阳几乎直射北回归线，是北半球一年中白昼最长的一天。夏至三候：鹿角解、蜩始鸣、半夏生。', '夏至是二十四节气中的第十个节气，这一天太阳几乎直射北回归线，是北半球一年中白昼最长的一天。夏至三候：鹿角解、蜩始鸣、半夏生。', '☀️', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','夏至'], 982, '夏至：日北至源远流长，可上溯至先秦时期。北半球白昼最长的一天、盛夏的开始、其形成与演变深受历代政治、经济、文化之影响。', '夏至：日北至作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"夏至：日北至是什么？","answer":"北半球白昼最长的一天，盛夏的开始。"},{"question":"夏至：日北至起源于何时？","answer":"根据史料记载，夏至：日北至的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"夏至：日北至有什么文化意义？","answer":"夏至：日北至承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-01-09T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 小寒：寒至极浅
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '小寒：寒至极浅', '节气', '天气寒冷，但未到极点。', '小寒是二十四节气中的第二十三个节气，标志着开始进入一年中最寒冷的日子，但此时还未达到最冷。', '小寒是二十四节气中的第二十三个节气，标志着开始进入一年中最寒冷的日子，但此时还未达到最冷。', '🥶', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','小寒'], 567, '小寒：寒至极浅源远流长，可上溯至先秦时期。天气寒冷、但未到极点、其形成与演变深受历代政治、经济、文化之影响。', '小寒：寒至极浅作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"小寒：寒至极浅是什么？","answer":"天气寒冷，但未到极点。"},{"question":"小寒：寒至极浅起源于何时？","answer":"根据史料记载，小寒：寒至极浅的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"小寒：寒至极浅有什么文化意义？","answer":"小寒：寒至极浅承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-03-27T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 小满：麦粒渐满
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '小满：麦粒渐满', '节气', '夏季节气之始，麦类等作物籽粒开始饱满但未成熟。', '小满是二十四节气中的第八个节气，夏季的第二个节气。其含义是夏熟作物的籽粒开始灌浆饱满，但还未成熟，只是小满。', '小满是二十四节气中的第八个节气，夏季的第二个节气。其含义是夏熟作物的籽粒开始灌浆饱满，但还未成熟，只是小满。', '🌾', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','小满'], 768, '小满：麦粒渐满源远流长，可上溯至先秦时期。夏季节气之始、麦类等作物籽粒开始饱满但未成熟、其形成与演变深受历代政治、经济、文化之影响。', '小满：麦粒渐满作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '黄河流域', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"小满：麦粒渐满是什么？","answer":"夏季节气之始，麦类等作物籽粒开始饱满但未成熟。"},{"question":"小满：麦粒渐满起源于何时？","answer":"根据史料记载，小满：麦粒渐满的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"小满：麦粒渐满有什么文化意义？","answer":"小满：麦粒渐满承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-05-19T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 小暑：温风至
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '小暑：温风至', '节气', '暑气渐盛，蝉鸣聒噪。', '小暑是二十四节气中的第十一个节气，夏季的第五个节气。暑，表示炎热的意思，小暑为小热，还不十分热。', '小暑是二十四节气中的第十一个节气，夏季的第五个节气。暑，表示炎热的意思，小暑为小热，还不十分热。', '🌤', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','小暑'], 567, '小暑：温风至源远流长，可上溯至先秦时期。暑气渐盛、蝉鸣聒噪、其形成与演变深受历代政治、经济、文化之影响。', '小暑：温风至作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"小暑：温风至是什么？","answer":"暑气渐盛，蝉鸣聒噪。"},{"question":"小暑：温风至起源于何时？","answer":"根据史料记载，小暑：温风至的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"小暑：温风至有什么文化意义？","answer":"小暑：温风至承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-06-22T06:06:26.222Z')
