-- 小雪：初雪轻盈
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '小雪：初雪轻盈', '节气', '初雪降临，雪量尚小，寒意渐浓。', '小雪是二十四节气中的第二十个节气，冬季的第二个节气。此时气温下降，但大地尚未过于寒冷，虽开始降雪但雪量不大，故称小雪。', '小雪是二十四节气中的第二十个节气，冬季的第二个节气。此时气温下降，但大地尚未过于寒冷，虽开始降雪但雪量不大，故称小雪。', '🌨', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','小雪'], 856, '小雪：初雪轻盈源远流长，可上溯至先秦时期。初雪降临、雪量尚小、寒意渐浓、其形成与演变深受历代政治、经济、文化之影响。', '小雪：初雪轻盈作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '周', '北方', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"小雪：初雪轻盈是什么？","answer":"初雪降临，雪量尚小，寒意渐浓。"},{"question":"小雪：初雪轻盈起源于何时？","answer":"根据史料记载，小雪：初雪轻盈的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"小雪：初雪轻盈有什么文化意义？","answer":"小雪：初雪轻盈承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-04-15T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 雨水：润物细无声
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '雨水：润物细无声', '节气', '春风化雨，草木萌动，万物开始复苏生长。', '雨水是二十四节气中的第二个节气。此时气温回升、冰雪融化、降水增多。雨水三候：獭祭鱼、鸿雁来、草木萌动。杜甫诗云：''好雨知时节，当春乃发生。随风潜入夜，润物细无声。''', '雨水是二十四节气中的第二个节气。此时气温回升、冰雪融化、降水增多。雨水三候：獭祭鱼、鸿雁来、草木萌动。杜甫诗云：''好雨知时节，当春乃发生。随风潜入夜，润物细无声。''', '💧', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节气','雨水'], 987, '雨水节气起源可追溯至先秦，《尚书·尧典》已有观测雏形，至汉代《淮南子·天文训》正式确立二十四节气体系，''雨水''位列第二。东汉崔寔《四民月令》详载雨水前后农事安排。魏晋以降，节气与道教''三元八节''及佛教信仰交融，宋代《东京梦华录》记汴京雨水日''市人以面制玉燕，插于发髻''。明清时期，《月令七十二候集解》系统阐释三候物象。', '雨水所承载的''润物无声''哲学，已成为中华文化中柔性力量与可持续智慧的象征。''随风潜入夜，润物细无声''启示尊重自然节律、反对粗暴干预的发展观；其物候观察传统为当代生物多样性监测提供方法论参照。在教育领域，''雨水启蒙''活动引导儿童辨识草木萌动，使节气成为自然教育的生动载体。', '上古', '汉', '全国', '[{"id":"dufu","title":"杜甫","category":"人物","brief":"盛唐诗人，《春夜喜雨》咏雨水"},{"id":"subaixie","title":"苏轼","category":"人物","brief":"一蓑烟雨任平生"}]'::jsonb, '[{"id":"shijing","title":"《诗经》","category":"典籍","brief":"收录众多春雨农事诗篇","external":true,"externalUrl":"https://baike.baidu.com/item/诗经"}]'::jsonb, '[{"id":"evt_yushuitaxing","title":"獭祭鱼","brief":"雨水三候之首，水獭捕鱼陈于岸"}]'::jsonb, '[{"id":"chunyexiyu","title":"春夜喜雨","category":"诗词","brief":"好雨知时节"},{"id":"dingfengbo","title":"定风波","category":"诗词","brief":"苏轼''莫听穿林打叶声''","external":true,"externalUrl":"https://baike.baidu.com/item/定风波"}]'::jsonb, '[{"id":"lichun","title":"立春：东风解冻","category":"节气"},{"id":"jingzhe","title":"惊蛰：春雷初响","category":"节气"}]'::jsonb, '[{"question":"雨水节气一定会下雨吗？","answer":"并非一定。雨水之名指冰雪消融、雨水增多之气候特征，并非''降雨日''。"},{"question":"雨水有哪些习俗？","answer":"北方有''拉保保''（认干爹）、''回娘屋''，南方则有占稻色、爆米花占岁等。","link":"evt_yushuitaxing"}]'::jsonb, '2025-12-13T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 春节：辞旧迎新
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-00000000000c', '春节：辞旧迎新', '节日', '农历正月初一，最隆重的传统节日，万家团圆。', '春节是农历正月初一，又叫阴历年，俗称''过年''。这是我国最隆重、最热闹、最富有民族特色的传统节日。春节历史悠久，由上古时代岁首祈岁祭祀演变而来。', '春节是农历正月初一，又叫阴历年，俗称''过年''。这是我国最隆重、最热闹、最富有民族特色的传统节日。春节历史悠久，由上古时代岁首祈岁祭祀演变而来。', '🧧', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节日','春节','过年'], 5890, '春节：辞旧迎新源远流长，可上溯至先秦时期。农历正月初一、最隆重的传统节日、万家团圆、其形成与演变深受历代政治、经济、文化之影响。', '春节：辞旧迎新作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '汉', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"春节：辞旧迎新是什么？","answer":"农历正月初一，最隆重的传统节日，万家团圆。"},{"question":"春节：辞旧迎新起源于何时？","answer":"根据史料记载，春节：辞旧迎新的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"春节：辞旧迎新有什么文化意义？","answer":"春节：辞旧迎新承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-06-09T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 冬至节：阳生之始
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '冬至节：阳生之始', '节日', '北方吃饺子、南方煮汤圆，祭祖迎阳。', '冬至是二十四节气之一，民间传统认为这一日''阴极之至，阳气始生''，故有''冬至大如年''之说。北方吃饺子、南方煮汤圆。', '冬至是二十四节气之一，民间传统认为这一日''阴极之至，阳气始生''，故有''冬至大如年''之说。北方吃饺子、南方煮汤圆。', '🍜', '《中华传统文化典籍》', '溯光编辑部', ARRAY['节日','冬至'], 1234, '冬至节：阳生之始源远流长，可上溯至先秦时期。北方吃饺子、南方煮汤圆、祭祖迎阳、其形成与演变深受历代政治、经济、文化之影响。', '冬至节：阳生之始作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '上古', '汉', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"冬至节：阳生之始是什么？","answer":"北方吃饺子、南方煮汤圆，祭祖迎阳。"},{"question":"冬至节：阳生之始起源于何时？","answer":"根据史料记载，冬至节：阳生之始的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"冬至节：阳生之始有什么文化意义？","answer":"冬至节：阳生之始承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-03-03T06:06:26.222Z')
ON CONFLICT (id) DO NOTHING;

-- 端午：汨罗江畔的千年追思
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-00000000000d', '端午：汨罗江畔的千年追思', '节日', '纪念屈原的传统节日，赛龙舟、食粽子、佩香囊。', '端午节，为每年农历五月初五。据《史记·屈原贾生列传》记载，屈原忠贞不渝却遭谗去职，流放至沅、湘流域。在写下绝笔《怀沙》后，抱石投汨罗江身死。', '端午节，为每年农历五月初五。据《史记·屈原贾生列传》记载，屈原忠贞不渝却遭谗去职，流放至沅、湘流域。在写下绝笔《怀沙》后，抱石投汨罗江身死。', '🐉', '《中华传统文化典籍》', '溯光编辑部', ARRAY['传统节日','屈原','龙舟','粽子'], 2391, '端午：汨罗江畔的千年追思源远流长，可上溯至先秦时期。纪念屈原的传统节日、赛龙舟、食粽子、佩香囊、其形成与演变深受历代政治、经济、文化之影响。', '端午：汨罗江畔的千年追思作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '战国', '战国', '南方', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"端午：汨罗江畔的千年追思是什么？","answer":"纪念屈原的传统节日，赛龙舟、食粽子、佩香囊。"},{"question":"端午：汨罗江畔的千年追思起源于何时？","answer":"根据史料记载，端午：汨罗江畔的千年追思的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"端午：汨罗江畔的千年追思有什么文化意义？","answer":"端午：汨罗江畔的千年追思承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-05-18T06:06:26.222Z')
