-- 阴阳五行：宇宙图式
INSERT INTO knowledge_articles (id, title, category, excerpt, body, body_extended, cover, source, author, tags, favorites, history, influence, era, dynasty, region, related_people, related_books, related_events, related_poems, related_articles, faq, created_at) VALUES
('a1b2c3d4-0002-0002-0002-000000000000', '阴阳五行：宇宙图式', '哲学', '阴阳消长，五行相生相克。', '阴阳五行是中国古代的一种哲学思想，认为宇宙间一切事物都由金、木、水、火、土五种物质构成。', '阴阳五行是中国古代的一种哲学思想，认为宇宙间一切事物都由金、木、水、火、土五种物质构成。', '☯', '《中华传统文化典籍》', '溯光编辑部', ARRAY['哲学','阴阳','五行'], 1789, '阴阳五行：宇宙图式源远流长，可上溯至先秦时期。阴阳消长、五行相生相克、其形成与演变深受历代政治、经济、文化之影响。', '阴阳五行：宇宙图式作为中华文化的重要组成部分，对后世产生了深远影响。不仅在文学艺术上有重要价值，更在思想观念、生活方式等方面塑造了民族精神。', '春秋', '战国', '全国', '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[{"question":"阴阳五行：宇宙图式是什么？","answer":"阴阳消长，五行相生相克。"},{"question":"阴阳五行：宇宙图式起源于何时？","answer":"根据史料记载，阴阳五行：宇宙图式的起源可追溯到先秦至两汉时期，并在后世不断丰富发展。"},{"question":"阴阳五行：宇宙图式有什么文化意义？","answer":"阴阳五行：宇宙图式承载着中华民族的文化记忆，是理解中华文明的重要窗口。"}]'::jsonb, '2026-02-28T06:06:26.222Z')
